import pytest

from calc import divide, percent


class TestDivide:
    def test_divide_basic(self):
        assert divide(10, 2) == 5

    def test_divide_floats(self):
        assert divide(7, 2) == 3.5

    def test_divide_negative_numerator(self):
        assert divide(-10, 2) == -5

    def test_divide_negative_denominator(self):
        assert divide(10, -2) == -5

    def test_divide_both_negative(self):
        assert divide(-10, -2) == 5

    def test_divide_by_zero(self):
        with pytest.raises(ValueError, match="cannot divide by zero"):
            divide(10, 0)

    def test_divide_zero_numerator(self):
        assert divide(0, 5) == 0

    def test_divide_fractions(self):
        result = divide(1, 3)
        assert abs(result - (1/3)) < 0.0001

    def test_divide_large_numbers(self):
        assert divide(1000000, 1000) == 1000

    def test_divide_small_numbers(self):
        result = divide(0.1, 0.2)
        assert abs(result - 0.5) < 0.0001


class TestPercent:
    def test_percent_basic(self):
        assert percent(25, 100) == 25

    def test_percent_half(self):
        assert percent(50, 100) == 50

    def test_percent_quarter(self):
        assert percent(1, 4) == 25

    def test_percent_with_decimals(self):
        assert percent(1.5, 100) == 1.5

    def test_percent_one_third(self):
        result = percent(1, 3)
        assert abs(result - 33.333333) < 0.001

    def test_percent_zero_part(self):
        assert percent(0, 100) == 0

    def test_percent_same_numbers(self):
        assert percent(100, 100) == 100

    def test_percent_small_numbers(self):
        assert percent(0.5, 100) == 0.5

    def test_percent_large_numbers(self):
        assert percent(500, 1000) == 50

    def test_percent_divide_by_zero(self):
        with pytest.raises(ValueError, match="cannot divide by zero"):
            percent(50, 0)

    def test_percent_negative_part(self):
        result = percent(-25, 100)
        assert result == -25

    def test_percent_negative_whole(self):
        result = percent(25, -100)
        assert result == -25

import pytest

from metrics import mean


class TestMean:
    def test_mean_basic(self):
        assert mean([1, 2, 3]) == 2

    def test_mean_two_values(self):
        assert mean([1, 3]) == 2

    def test_mean_single_value(self):
        assert mean([5]) == 5

    def test_mean_floats(self):
        assert mean([1.5, 2.5, 3.0]) == pytest.approx(2.333333, rel=1e-5)

    def test_mean_negative_numbers(self):
        assert mean([-1, -2, -3]) == -2

    def test_mean_mixed_positive_negative(self):
        assert mean([-10, 0, 10]) == 0

    def test_mean_zero_values(self):
        assert mean([0, 0, 0]) == 0

    def test_mean_large_numbers(self):
        assert mean([1000, 2000, 3000]) == 2000

    def test_mean_small_decimals(self):
        result = mean([0.1, 0.2, 0.3])
        assert abs(result - 0.2) < 0.0001

    def test_mean_fractional_result(self):
        result = mean([1, 2, 3, 4, 5])
        assert result == 3

    def test_mean_many_values(self):
        values = list(range(1, 101))  # 1 to 100
        assert mean(values) == 50.5

    def test_mean_empty_raises(self):
        with pytest.raises(ValueError, match="no values"):
            mean([])

    def test_mean_alternating_values(self):
        assert mean([1, 10, 1, 10]) == 5.5

    def test_mean_repeating_values(self):
        assert mean([7, 7, 7, 7]) == 7

    def test_mean_two_halves(self):
        result = mean([0.5, 0.5])
        assert result == 0.5

